mapper.update:
update courseselection
normal_score = #{normalScore}, test_score = #{testScore},
where sno = #{sno} and cno = #{cno}

mapper.select:
select sno as "sno", sname as "sname", cno as "cno", cname as "cname", credit as "credit", semester as "semester", normal_score as "normalScore", test_score as "testScore", total_score as "totalScore", grade_point as "gradePoint" from v_student_grades

    and sno = #{sno}

order by semester, cno
